import { BufferAttribute, BufferGeometry } from 'three';

export class SerializedGeometry {
    position: ArrayLike<number>;
    normal: ArrayLike<number>;
    expressID: ArrayLike<number>;
    index: ArrayLike<number>;
    groups: { start: number, count: number, materialIndex?: number }[];

    constructor(geometry: BufferGeometry) {
        this.position = (geometry.attributes.position as BufferAttribute)?.array || [];
        this.normal = (geometry.attributes.normal as BufferAttribute)?.array || [];
        this.expressID = (geometry.attributes.expressID as BufferAttribute)?.array || [];
        this.index = geometry.index?.array || [];
        this.groups = geometry.groups;
    }
}

export class GeometryReconstructor {
    static new(serialized: SerializedGeometry) {
        const geom = new BufferGeometry();
        GeometryReconstructor.set(geom, 'expressID', new Uint32Array(serialized.expressID), 1);
        GeometryReconstructor.set(geom, 'position', new Float32Array(serialized.position), 3);
        GeometryReconstructor.set(geom, 'normal', new Float32Array(serialized.normal), 3);
        geom.setIndex(Array.from(serialized.index));
        geom.groups = serialized.groups;
        return geom;
    }

    private static set(geom: BufferGeometry, name: string, data: ArrayLike<number>, size: number) {
        if(data.length > 0) {
            geom.setAttribute(name, new BufferAttribute(data, size));
        }
    }
}

import { IFCModel } from '../../components/IFCModel';
import { Material, MeshLambertMaterial } from 'three';
import { MaterialReconstructor, SerializedMaterial } from './Material';
import { GeometryReconstructor, SerializedGeometry } from './Geometry';

export class SerializedMesh {

    modelID: number;
    geometry: SerializedGeometry;
    materials: SerializedMaterial [] = [];

    constructor(model: IFCModel) {
        this.modelID = model.modelID;
        this.geometry = new SerializedGeometry(model.geometry);
        if (Array.isArray(model.material)) {
            model.material.forEach(mat => {
                this.materials.push(new SerializedMaterial(mat as MeshLambertMaterial));
            });
        } else {
            this.materials.push(new SerializedMaterial(model.material as MeshLambertMaterial));
        }
    }
}

export class MeshReconstructor {

    static new(serialized: SerializedMesh) {
        const model = new IFCModel();
        model.modelID = serialized.modelID;
        model.geometry = GeometryReconstructor.new(serialized.geometry);
        MeshReconstructor.getMaterials(serialized, model);
        return model;
    }

    private static getMaterials(serialized: SerializedMesh, model: IFCModel) {
        model.material = [];
        const mats = model.material as Material[];
        serialized.materials.forEach(mat => {
            mats.push(MaterialReconstructor.new(mat));
        });
    }
}

import { Vector as WebIfcVector, IfcGeometry as WebIfcIfcGeometry, FlatMesh as WebIfcFlatMesh } from 'web-ifc';
import { SerializedFlatMesh, SerializedIfcGeometry, SerializedVector } from '../BaseDefinitions';
import { Vector } from './Vector';
import { IfcGeometry } from './IfcGeometry';
import { FlatMesh } from './FlatMesh';
import { FlatMeshVector } from './FlatMeshVector';
import { IFCModel } from '../../components/IFCModel';
import { MeshReconstructor, SerializedMesh } from './Mesh';

export class Serializer {

    serializeVector<T>(vector: WebIfcVector<T>) {
        const size = vector.size();
        const serialized: SerializedVector = { size };
        for (let i = 0; i < size; i++) {
            serialized[i] = vector.get(i);
        }
        return serialized;
    }

    reconstructVector(vector: SerializedVector): Vector<any> {
        return new Vector(vector);
    }

    serializeIfcGeometry(geometry: WebIfcIfcGeometry) {
        const GetVertexData = geometry.GetVertexData();
        const GetVertexDataSize = geometry.GetVertexDataSize();
        const GetIndexData = geometry.GetIndexData();
        const GetIndexDataSize = geometry.GetIndexDataSize();
        return {
            GetVertexData,
            GetVertexDataSize,
            GetIndexData,
            GetIndexDataSize
        } as SerializedIfcGeometry;
    }

    reconstructIfcGeometry(geometry: SerializedIfcGeometry) {
        return new IfcGeometry(geometry);
    }

    serializeFlatMesh(flatMesh: WebIfcFlatMesh) {
        return {
            expressID: flatMesh.expressID,
            geometries: this.serializeVector(flatMesh.geometries)
        } as SerializedFlatMesh;
    }

    reconstructFlatMesh(flatMesh: SerializedFlatMesh) {
        return new FlatMesh(this, flatMesh);
    }

    serializeFlatMeshVector(vector: WebIfcVector<WebIfcFlatMesh>) {
        const size = vector.size();
        const serialized: SerializedVector = { size };
        for (let i = 0; i < size; i++) {
            const flatMesh = vector.get(i);
            serialized[i] = this.serializeFlatMesh(flatMesh);
        }
        return serialized;
    }

    reconstructFlatMeshVector(vector: SerializedVector): WebIfcVector<WebIfcFlatMesh> {
        return new FlatMeshVector(this, vector);
    }

    serializeIfcModel(model: IFCModel) {
        return new SerializedMesh(model);
    }

    reconstructIfcModel(model: SerializedMesh) {
        return MeshReconstructor.new(model);
    }
}

